import{_ as p,r as o,o as e,c,a as s,b as n,d as l,e as r}from"./app.547295de.js";var t="/assets/home-logo.webp?v=20260525-nt";const B={},i={align:"center"},y=s("h1",{id:"next-trainer",class:"sr-only",tabindex:"-1"},[s("a",{class:"header-anchor",href:"#next-trainer","aria-hidden":"true"},"#"),n(" Next Trainer")],-1),C=s("img",{src:t,width:"300",height:"300",alt:"Next Trainer",class:"sd-home-logo",loading:"lazy"},null,-1),E=s("p",null,"lora-scripts-next \u00b7 \u4e0b\u4e00\u4ee3\u8bad\u7ec3 WebUI",-1),A={href:"https://github.com/wochenlong",target:"_blank",rel:"noopener noreferrer"},d={href:"https://github.com/wochenlong/lora-scripts-next",target:"_blank",rel:"noopener noreferrer"},h=r(`<p align="center"><a href="https://github.com/wochenlong/lora-scripts-next" style="margin:2px;"><img alt="GitHub Repo stars" src="https://img.shields.io/github/stars/wochenlong/lora-scripts-next"></a><a href="https://github.com/wochenlong/lora-scripts-next" style="margin:2px;"><img alt="GitHub forks" src="https://img.shields.io/github/forks/wochenlong/lora-scripts-next"></a><a href="https://raw.githubusercontent.com/wochenlong/lora-scripts-next/master/LICENSE" style="margin:2px;"><img src="https://img.shields.io/github/license/wochenlong/lora-scripts-next" alt="license"></a><a href="https://github.com/wochenlong/lora-scripts-next/releases" style="margin:2px;"><img src="https://img.shields.io/github/v/release/wochenlong/lora-scripts-next?color=blueviolet&amp;include_prereleases" alt="release"></a></p><div class="sd-home-onboarding"><h2 id="项目简介" tabindex="-1"><a class="header-anchor" href="#项目简介" aria-hidden="true">#</a> 项目简介</h2><p><strong>SD-Trainer</strong> 是基于秋叶版 <a href="https://github.com/Akegarasu/lora-scripts" target="_blank" rel="noopener noreferrer">lora-scripts</a> 的 Stable Diffusion 训练 WebUI（本 fork：<a href="https://github.com/wochenlong/lora-scripts-next" target="_blank" rel="noopener noreferrer">lora-scripts-next</a>）。在浏览器里配置模型路径、数据集与训练参数，一键启动训练；支持 LoRA、Dreambooth、Anima、Flux 等。</p><h2 id="新手上路" tabindex="-1"><a class="header-anchor" href="#新手上路" aria-hidden="true">#</a> 新手上路</h2><ol><li><strong>准备数据</strong>：图片 + 同名标签文件；可用左侧「工具与调试 → 数据集打标」。</li><li><strong>选训练类型</strong>：<ul><li>LoRA：<a href="/lora/sd3.html"><strong>Anima</strong></a>、<a href="/lora/flux.html"><strong>Flux</strong></a>、<a href="/lora/master.html"><strong>Stable Diffusion</strong></a></li><li>全量微调：<a href="/lora/anima-finetune.html"><strong>Anima Finetune</strong></a>（完整 DiT，约 24GB 显存）、<a href="/dreambooth/index.html"><strong>Stable Diffusion</strong></a>（Dreambooth / SDXL）</li></ul></li><li><strong>填参数并开训</strong>：中栏表单 + 右栏「开始训练」；进度可开 <a href="/tensorboard.html">Tensorboard</a> 或 <a href="/train-monitor">训练监控</a>。</li></ol><h2 id="从秋叶版迁移" tabindex="-1"><a class="header-anchor" href="#从秋叶版迁移" aria-hidden="true">#</a> 从秋叶版迁移</h2><p>若你习惯原 <strong>Akegarasu/lora-scripts</strong>（秋叶一键包），本版主要变化如下：</p><ul><li><strong>导航</strong>：按「训练 / 工具 / 帮助 / 其他」分组；LoRA 下聚合 Anima、Flux、SD；原「新手 / 专家」不再平铺于侧栏（SD1.5 精简页仍可访问 <a href="/lora/basic.html">/lora/basic.html</a>）。</li><li><strong>Anima</strong>：原 SD3 位置改为 Anima 训练（Qwen + T5 + DiT）。</li><li><strong>监控</strong>：独立训练监控页、Loss 曲线、实时日志（<code>/train-log</code>）。</li><li><strong>其他</strong>：便携包优化、Flash Attention 自动加速、AMD 提示等（详见 <a href="/other/changelog.html">更新日志</a>）。</li></ul><p class="sd-home-tip">参数含义见「帮助 → 训练参数说明」；反馈与联系方式见「其他 → 关于」。</p></div>`,10);function F(u,g){const a=o("ExternalLinkIcon");return e(),c("div",null,[s("div",i,[y,C,E,s("p",null,[n("Author "),s("a",A,[n("wochenlong"),l(a)]),n(" Github "),s("a",d,[n("lora-scripts"),l(a)])])]),h])}var b=p(B,[["render",F],["__file","index.html.vue"]]);export{b as default};
